&lt;li data-leveltext=&quot;&quot; data-font=&quot;Symbol&quot; data-listid=&quot;2&quot; data-aria-posinset=&quot;2&quot; data-aria-level=&quot;1&quot;&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Design, develop, implement and support complex critical applications&lt;/span&gt;&lt;span data-ccp-props=&quot;{&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
